static int crc16Modbus(byte[] data) {
    int crc = 0xFFFF;
    for (byte value : data) {
        crc ^= Byte.toUnsignedInt(value);
        for (int bit = 0; bit < 8; bit++) {
            crc = (crc & 1) != 0 ? (crc >>> 1) ^ 0xA001 : crc >>> 1;
        }
    }
    return crc & 0xFFFF;
}

