final class Pid {
    private final double kp, ki, kd;
    private double integral, previousError;

    double update(double setpoint, double measured, double dt) {
        double error = setpoint - measured;
        integral += error * dt;
        double derivative = (error - previousError) / dt;
        previousError = error;
        return kp * error + ki * integral + kd * derivative;
    }
}

enum State { IDLE, CONNECTING, RUNNING, ERROR }

void handle(Event event) {
    switch (state) {
        case IDLE -> { if (event == Event.START) state = State.CONNECTING; }
        case CONNECTING -> { if (event == Event.CONNECTED) state = State.RUNNING; }
        case RUNNING -> { if (event == Event.FAIL) state = State.ERROR; }
        case ERROR -> { if (event == Event.RESET) state = State.IDLE; }
    }
}

